"""rAIdio.bot replacement for fairseq.checkpoint_utils.

ComfyUI-RVC's extract_feature_print.py calls
`fairseq.checkpoint_utils.load_model_ensemble_and_task([path], suffix="")`
to load a fairseq HuBERT-base checkpoint and use it for feature
extraction during voice training.

This module reimplements that function on top of
transformers.HubertModel (already shipped in our embedded Python).
The fairseq state_dict is remapped to HF key naming, loaded into
HubertModel, and wrapped in a thin class that exposes the
fairseq-style API (`extract_features(source, padding_mask, output_layer)`
returning `(features_tensor, padding_mask)` tuple).

License: GPL-3.0.
Source: https://github.com/rAIdio-bot/rAIdio-nodes
"""

import os
import sys

import torch


# ---------------------------------------------------------------------
# Attribute-access wrapper for the cfg dict
# ---------------------------------------------------------------------

class _AttrDict:
    """Recursive dict→object wrapper. The fairseq HuBERT-base checkpoint
    pickles cfg as a nested dict (e.g. cfg['task']['normalize']), but
    ComfyUI-RVC's extract_feature_print.py:116 reads it as
    `saved_cfg.task.normalize`. Wrap so attribute access works."""

    def __init__(self, d):
        if isinstance(d, dict):
            for k, v in d.items():
                if isinstance(v, dict):
                    v = _AttrDict(v)
                elif isinstance(v, (list, tuple)):
                    v = type(v)(
                        _AttrDict(x) if isinstance(x, dict) else x for x in v
                    )
                object.__setattr__(self, str(k), v)

    def __getattr__(self, name):
        if name.startswith("_"):
            raise AttributeError(name)
        return None

    def __getitem__(self, key):
        return getattr(self, str(key), None)

    def __contains__(self, key):
        return hasattr(self, str(key))


# ---------------------------------------------------------------------
# fairseq → HuggingFace HuBERT state_dict key mapping
# ---------------------------------------------------------------------

def _fairseq_to_hf_hubert(fairseq_sd, num_layers=12, num_conv=7):
    """Map a fairseq HuBERT-base state_dict to HuggingFace HubertModel
    keys (transformers ~4.30+).

    Drops pretraining-only keys (mask_emb, label_embs_concat,
    final_proj.*) since extract_feature_print.py for v2 doesn't use
    them. final_proj weights are returned separately via the wrapper
    so the v1 path can still apply final_proj if needed."""
    hf_sd = {}

    # 7-conv feature extractor — Conv1d weights for all layers
    for i in range(num_conv):
        hf_sd[f"feature_extractor.conv_layers.{i}.conv.weight"] = (
            fairseq_sd[f"feature_extractor.conv_layers.{i}.0.weight"]
        )
    # Layer 0 has GroupNorm (fairseq's `.2` index in the original Sequential)
    hf_sd["feature_extractor.conv_layers.0.layer_norm.weight"] = (
        fairseq_sd["feature_extractor.conv_layers.0.2.weight"]
    )
    hf_sd["feature_extractor.conv_layers.0.layer_norm.bias"] = (
        fairseq_sd["feature_extractor.conv_layers.0.2.bias"]
    )

    # Top-level layer_norm + post_extract_proj → HF feature_projection.*
    hf_sd["feature_projection.layer_norm.weight"] = fairseq_sd["layer_norm.weight"]
    hf_sd["feature_projection.layer_norm.bias"] = fairseq_sd["layer_norm.bias"]
    hf_sd["feature_projection.projection.weight"] = fairseq_sd["post_extract_proj.weight"]
    hf_sd["feature_projection.projection.bias"] = fairseq_sd["post_extract_proj.bias"]

    # Positional convolution (weight_norm parametrization preserved)
    hf_sd["encoder.pos_conv_embed.conv.bias"] = fairseq_sd["encoder.pos_conv.0.bias"]
    hf_sd["encoder.pos_conv_embed.conv.weight_g"] = fairseq_sd["encoder.pos_conv.0.weight_g"]
    hf_sd["encoder.pos_conv_embed.conv.weight_v"] = fairseq_sd["encoder.pos_conv.0.weight_v"]

    # Encoder final layer_norm
    hf_sd["encoder.layer_norm.weight"] = fairseq_sd["encoder.layer_norm.weight"]
    hf_sd["encoder.layer_norm.bias"] = fairseq_sd["encoder.layer_norm.bias"]

    # Transformer layers
    for i in range(num_layers):
        for proj in ("k_proj", "v_proj", "q_proj", "out_proj"):
            hf_sd[f"encoder.layers.{i}.attention.{proj}.weight"] = (
                fairseq_sd[f"encoder.layers.{i}.self_attn.{proj}.weight"]
            )
            hf_sd[f"encoder.layers.{i}.attention.{proj}.bias"] = (
                fairseq_sd[f"encoder.layers.{i}.self_attn.{proj}.bias"]
            )
        hf_sd[f"encoder.layers.{i}.layer_norm.weight"] = (
            fairseq_sd[f"encoder.layers.{i}.self_attn_layer_norm.weight"]
        )
        hf_sd[f"encoder.layers.{i}.layer_norm.bias"] = (
            fairseq_sd[f"encoder.layers.{i}.self_attn_layer_norm.bias"]
        )
        hf_sd[f"encoder.layers.{i}.feed_forward.intermediate_dense.weight"] = (
            fairseq_sd[f"encoder.layers.{i}.fc1.weight"]
        )
        hf_sd[f"encoder.layers.{i}.feed_forward.intermediate_dense.bias"] = (
            fairseq_sd[f"encoder.layers.{i}.fc1.bias"]
        )
        hf_sd[f"encoder.layers.{i}.feed_forward.output_dense.weight"] = (
            fairseq_sd[f"encoder.layers.{i}.fc2.weight"]
        )
        hf_sd[f"encoder.layers.{i}.feed_forward.output_dense.bias"] = (
            fairseq_sd[f"encoder.layers.{i}.fc2.bias"]
        )
        hf_sd[f"encoder.layers.{i}.final_layer_norm.weight"] = (
            fairseq_sd[f"encoder.layers.{i}.final_layer_norm.weight"]
        )
        hf_sd[f"encoder.layers.{i}.final_layer_norm.bias"] = (
            fairseq_sd[f"encoder.layers.{i}.final_layer_norm.bias"]
        )

    return hf_sd


# ---------------------------------------------------------------------
# fairseq-style wrapper around HuggingFace HubertModel
# ---------------------------------------------------------------------

class _HubertFairseqWrapper(torch.nn.Module):
    """Wraps a transformers.HubertModel and exposes the fairseq-style
    `extract_features(source, padding_mask, output_layer)` returning a
    `(features_tensor, padding_mask)` tuple.

    ComfyUI-RVC's extract_feature_print.py uses this exact shape:
        logits = model.extract_features(source=feats, padding_mask=mask,
                                        output_layer=12)
        feats = logits[0]                 # (B, T_features, 768)

    For v1, the same script applies `model.final_proj(logits[0])` to get
    a 256-dim projection — we copy fairseq's final_proj weights into a
    standard nn.Linear so that path keeps working."""

    def __init__(self, hf_model, final_proj_weight=None, final_proj_bias=None):
        super().__init__()
        self.hf_model = hf_model
        if final_proj_weight is not None:
            out_dim, in_dim = final_proj_weight.shape
            self.final_proj = torch.nn.Linear(in_dim, out_dim)
            with torch.no_grad():
                self.final_proj.weight.copy_(final_proj_weight)
                if final_proj_bias is not None:
                    self.final_proj.bias.copy_(final_proj_bias)

    def extract_features(self, source, padding_mask=None, output_layer=12):
        # source: (B, T_audio) fp16 or fp32 audio waveform at 16 kHz
        # padding_mask: (B, T_audio) bool — fairseq convention: True = padded
        # HF attention_mask: 1 = attend, 0 = pad — opposite
        attention_mask = None
        if padding_mask is not None:
            attention_mask = (~padding_mask).to(torch.long)

        outputs = self.hf_model(
            input_values=source,
            attention_mask=attention_mask,
            output_hidden_states=True,
            return_dict=True,
        )
        # hidden_states[0]      = post-feature-extractor embeddings
        # hidden_states[k]      = output AFTER transformer layer k (k=1..N)
        # fairseq output_layer  = last layer to extract from (1-indexed)
        feats = outputs.hidden_states[output_layer]
        return feats, padding_mask


# ---------------------------------------------------------------------
# Public entry point matching fairseq.checkpoint_utils.load_model_ensemble_and_task
# ---------------------------------------------------------------------

def load_model_ensemble_and_task(filenames, suffix=""):
    """Replacement for fairseq.checkpoint_utils.load_model_ensemble_and_task.

    Loads a fairseq HuBERT-base checkpoint and returns a
    `(models, saved_cfg, task)` tuple where:
      - models[0] is an nn.Module exposing fairseq-style
        `extract_features(source, padding_mask, output_layer)`.
      - saved_cfg is the checkpoint's cfg object (provides `.task.normalize`).
      - task is None (ComfyUI-RVC doesn't use it).
    """
    if not filenames or not isinstance(filenames, (list, tuple)):
        raise ValueError(
            "load_model_ensemble_and_task expects a non-empty list of paths"
        )
    path = filenames[0]
    if not os.path.exists(path):
        raise FileNotFoundError(f"HuBERT checkpoint not found: {path}")

    print(
        f"[rAIdio fairseq-shim] loading HuBERT from {os.path.basename(path)} "
        "via transformers.HubertModel",
        file=sys.stderr,
        flush=True,
    )

    # Load the fairseq checkpoint. weights_only=False because the pickle
    # references fairseq classes (Dictionary, FairseqConfig, etc.) that
    # our sibling stub modules provide.
    sd = torch.load(path, map_location="cpu", weights_only=False)
    if not isinstance(sd, dict) or "model" not in sd:
        raise RuntimeError(
            f"Unexpected checkpoint structure in {path}: top-level type "
            f"{type(sd).__name__}, keys={list(sd.keys()) if isinstance(sd, dict) else 'N/A'}"
        )

    fairseq_sd = sd["model"]
    if not isinstance(fairseq_sd, dict):
        raise RuntimeError(
            f"Expected sd['model'] to be a dict, got {type(fairseq_sd).__name__}"
        )

    hf_sd = _fairseq_to_hf_hubert(fairseq_sd)

    # Build a HuggingFace HubertModel matching fairseq HuBERT-base config.
    # These values are derived from the fairseq HuBERT-base checkpoint
    # (12 layers, 768 hidden, 12 heads, 7-conv feature extractor with
    # GroupNorm on layer 0, kernels 10/3/3/3/3/2/2, strides 5/2/2/2/2/2/2).
    from transformers import HubertConfig, HubertModel

    config = HubertConfig(
        hidden_size=768,
        num_hidden_layers=12,
        num_attention_heads=12,
        intermediate_size=3072,
        hidden_act="gelu",
        feat_extract_norm="group",
        feat_extract_activation="gelu",
        feat_proj_dropout=0.0,
        feat_proj_layer_norm=True,
        layerdrop=0.0,
        activation_dropout=0.1,
        attention_dropout=0.1,
        hidden_dropout=0.1,
        final_dropout=0.1,
        layer_norm_eps=1e-5,
        conv_dim=(512, 512, 512, 512, 512, 512, 512),
        conv_stride=(5, 2, 2, 2, 2, 2, 2),
        conv_kernel=(10, 3, 3, 3, 3, 2, 2),
        conv_bias=False,
        num_conv_pos_embeddings=128,
        num_conv_pos_embedding_groups=16,
        do_stable_layer_norm=False,
    )
    model = HubertModel(config)

    # strict=False: HF HubertModel has `masked_spec_embed` as a buffer/param
    # that the fairseq inference checkpoint does not provide; we leave it
    # at its random init (it's never used in inference forward path).
    missing, unexpected = model.load_state_dict(hf_sd, strict=False)

    benign_missing = {"masked_spec_embed"}
    real_missing = [k for k in missing if k not in benign_missing]
    if real_missing:
        print(
            f"[rAIdio fairseq-shim] WARNING: missing keys after load "
            f"({len(real_missing)}): {real_missing[:8]}{'...' if len(real_missing) > 8 else ''}",
            file=sys.stderr,
            flush=True,
        )
    if unexpected:
        print(
            f"[rAIdio fairseq-shim] WARNING: unexpected keys "
            f"({len(unexpected)}): {unexpected[:8]}{'...' if len(unexpected) > 8 else ''}",
            file=sys.stderr,
            flush=True,
        )

    final_proj_w = fairseq_sd.get("final_proj.weight")
    final_proj_b = fairseq_sd.get("final_proj.bias")
    wrapper = _HubertFairseqWrapper(model, final_proj_w, final_proj_b)
    wrapper.eval()

    raw_cfg = sd.get("cfg")
    saved_cfg = _AttrDict(raw_cfg) if isinstance(raw_cfg, dict) else raw_cfg
    task = None  # ComfyUI-RVC reads only saved_cfg.task.normalize, not the task object

    print(
        "[rAIdio fairseq-shim] HuBERT loaded successfully "
        f"(missing={len(real_missing)}, unexpected={len(unexpected)})",
        file=sys.stderr,
        flush=True,
    )
    return [wrapper], saved_cfg, task
